// Add a task to the shared task database.
// Input: JSON string with { title, description, assignedTo, priority }
// assignedTo should be 'executor'. priority: 'high','medium','low'
var task = JSON.parse(input);
if (!globalThis.taskDb) globalThis.taskDb = [];
var id = 'task_' + (globalThis.taskDb.length + 1);
var newTask = {
  id: id,
  title: task.title || 'Untitled',
  description: task.description || '',
  assignedTo: task.assignedTo || 'executor',
  priority: task.priority || 'medium',
  status: 'pending',
  result: null,
  createdAt: new Date().toISOString()
};
globalThis.taskDb.push(newTask);
return JSON.stringify({ success: true, task: newTask, totalTasks: globalThis.taskDb.length });

// List tasks from the shared database.
// Input: filter string — 'all', 'pending', 'in_progress', 'completed', or 'approved'
if (!globalThis.taskDb) globalThis.taskDb = [];
var filter = (input || 'all').trim().toLowerCase();
var tasks = globalThis.taskDb;
if (filter !== 'all') {
  tasks = globalThis.taskDb.filter(function(t) { return t.status === filter; });
}
return JSON.stringify({ filter: filter, count: tasks.length, tasks: tasks });

// Update a task in the shared database.
// Input: JSON string with { id, status?, result?, assignedTo?, notes? }
// status values: 'pending','in_progress','completed','approved'
var update = JSON.parse(input);
if (!globalThis.taskDb) globalThis.taskDb = [];
var task = null;
for (var i = 0; i < globalThis.taskDb.length; i++) {
  if (globalThis.taskDb[i].id === update.id) { task = globalThis.taskDb[i]; break; }
}
if (!task) return JSON.stringify({ success: false, error: 'Task not found: ' + update.id });
if (update.status) task.status = update.status;
if (update.result !== undefined) task.result = update.result;
if (update.assignedTo) task.assignedTo = update.assignedTo;
if (update.notes) task.notes = update.notes;
task.updatedAt = new Date().toISOString();
return JSON.stringify({ success: true, task: task });

